VALUES
  ('social-worker-moex-05440', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社區發展協會為基層社區推動之組織，下列有關社區發展協會的組織性質，何者錯誤？', '["非營利性質的人民團體", "組織的財源來自會費、捐款或其他補助收入", "理事會為最高權力機關", "由社區居民，年滿20歲，有30個人以上發起"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05441', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關從工業革命到慈善組織會社的歷史發展歷程，何者錯誤？', '["在中世紀以前西方基督教社會裡，救濟貧民的工作主要由教會來承擔", "1601年伊莉莎白女王公布的濟貧法，為今日社會福利的直接源頭", "1782年通過「史賓漢蘭制」，鼓勵組成濟貧工會並恢復院外救濟方式", "「史賓漢蘭制」也實施普及的食物量表，以家庭維持基本生計所需麵包價格為基準，來救濟貧民"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05442', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社區工作模式中，最廣為引用的首推樓斯曼（Rothman）於 1968 年提出三種模式：地方發展、社會計 畫、社會行動。有關各種模式的敘述，下列何者錯誤？', '["地方發展的改變策略是納入更多人，以決定並解決其問題", "社會計畫的改變方法與技巧是形成共識或衝突", "社會行動的改變策略是蒐集問題資料，並採取最合理的行動", "Rothman 承認各個模式間會有交互混用的狀況，於是進一步分析模式間的重疊與混合，成為十二種社 區介入典範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05443', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '案主之所以需要社會服務的協助，可能是在生活層面上遇到自己難以克服的障礙，其中外在障礙是因案 主環境的不足而無法提供所需的協助，這些障礙是外在於案主的，且不是案主所能控制或影響。下列何 者不是外在障礙的原因之一？', '["資源雖存在但案主沒有企圖獲得相關訊息", "資源不存在或不足以滿足需求", "資源雖然存在但所需的補助資源並不存在", "資源雖存在但不適用於特定案主"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05444', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '請問下列何者並不屬於全球化對社會工作的影響範疇？', '["不確定性", "本土價值與殖民價值的融合", "專業關係的建立與新公共管理效率考量的衝突", "新自由主義下全球化的困境，如：貧富不均、工作貧窮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05445', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '隨著老人人口的增加與壽命的延長，因老化而延伸出的議題愈來愈受到重視，其中老人虐待與疏忽（elder abuse and neglect）的議題就十分值得關心與探討。下列有關老人虐待與疏忽的敘述，何者錯誤？', '["每當有一個老人虐待或疏忽的個案被發覺，意味著另外至少還有5個老人虐待或疏忽事件沒有被發現", "據統計受到虐待或疏忽的老人死於心臟病、癌症、腎臟病，或是意外傷害的機率僅是沒有受到虐待或 疏忽老人的三分之一", "可能的施虐對象通常是家庭成員，像是配偶，更常見的情形是成年子女", "失能程度較高的受虐者、照顧者有照顧負荷與壓力以及長期的經濟壓力，都是造成老人虐待與疏忽的 危險因子，再加上老人孤立的情況，會有高度的老人受虐危機"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05446', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會救助的特質，何者錯誤？', '["生存權保障原則", "普遍照顧原則", "親屬責任原則", "國家責任原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05447', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'essay', '社區工作目標之一是讓社區居民參與改造社區，讓社區變得更好。某兒童福利組織
位於整個都市中最早發展也曾經相當繁榮，但今日已是相當老舊的社區；社區內有
許多情色場所、賭博與電動遊樂場、幫派組織，社區中未成年的青少年常因為各種
因素輟學或進入司法矯治機構。請說明該社區內的兒童福利組織社會工作者如何應
用「地方發展模式」（locality development）或「自助模式」（self-help）去改善該
社區兒少生活狀況。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "a862c6a7c899", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05448', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'essay', '社會工作者在執行個案工作時常需與個案密切互動，以了解個案需求與問題，因此
社會工作者在個案工作中的專業關係也就格外重要。請說明社會工作者應該在社會
個案工作中掌握那些重要的專業關係原則。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "a862c6a7c899", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05449', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Rubin &Rubin（2008）認為社區能力不管著重於個人或組織層面，都應該包括下列那幾個因素？', '["存在的資源、網絡的關係、領導、支持成員集體參與行動與共同解決問題的機制", "社區意識、社區成員間相互委身的程度、解決問題的能力、資源的可近性", "社區中的人力、物力、組織資源與社區關係所形成的社區能力", "資源能力、組織能力、方案能力、網絡能力、政治能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "a862c6a7c899", "answer_pdf_sha1": "af41ff06817a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
